#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5;
struct Player{
	int s,w,id;
}p[N];
bool cmp(Player x,Player y){
	if(x.s==y.s)
		return x.id<y.id;
	return x.s>y.s;
}
int n,r,q;
int main(){
	scanf("%d%d%d",&n,&r,&q);
	for(int i=1;i<=2*n;i++)
		scanf("%d",&p[i].s);
	for(int i=1;i<=2*n;i++){
		scanf("%d",&p[i].w);
		p[i].id=i;
	}
	for(int i=1;i<=r;i++){
		stable_sort(p+1,p+2*n+1,cmp);
		for(int j=1;j<=2*n;j+=2){
			if(p[j].w>p[j+1].w)
				p[j].s++;
			else
				p[j+1].s++;
		}
	}
	sort(p+1,p+2*n+1,cmp);
	printf("%d",p[q].id);
	return 0;
}
